import { useStore } from './store'; // Import the store to get your nodes and edges

export const SubmitButton = () => {
  const { nodes, edges } = useStore();

  const handleSubmit = async () => {
    const formData = new FormData();

    // Convert your ReactFlow nodes and edges into the format FastAPI expects
    formData.append('nodes', JSON.stringify(nodes.map(n => n.id)));
    formData.append('edges', JSON.stringify(edges.map(e => `${e.source}->${e.target}`)));

    try {
      const response = await fetch('http://127.0.0.1:8000/pipelines/parse', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      // Tell the user what the backend found
      alert(`Nodes: ${data.num_nodes}, Edges: ${data.num_edges}, Is DAG: ${data.is_dag}`);

    } catch (error) {
      console.error("Error connecting to backend:", error);
      alert("Could not connect to backend. Make sure Uvicorn is running!");
    }
  };

  return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', marginTop: '20px' }}>
      <button onClick={handleSubmit}>Submit</button>
    </div>
  );
};
